CREATE TABLE org_provider_profile (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL REFERENCES organizations(id), person_id uuid NOT NULL REFERENCES persons(id), provider_type text NOT NULL DEFAULT 'clinician', specialties text[] DEFAULT ARRAY[]::text[], title text, contract_type text DEFAULT 'employee', employment_type text DEFAULT 'full_time', start_date date, end_date date, license_number text, license_type text, commission_rate numeric, hourly_rate numeric, certifications jsonb DEFAULT '[]'::jsonb, availability_preferences jsonb DEFAULT '{}'::jsonb, metadata jsonb DEFAULT '{}'::jsonb, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), UNIQUE(organization_id, person_id)); ALTER TABLE org_provider_profile ADD CONSTRAINT org_provider_profile_provider_type_check CHECK (provider_type IN ('clinician','trainer','pilates_instructor','wellness_coach','occupational_therapist','speech_therapist','psychologist','exercise_specialist','researcher')); ALTER TABLE org_provider_profile ADD CONSTRAINT org_provider_profile_contract_type_check CHECK (contract_type IN ('employee','freelancer','contractor','volunteer','intern')); ALTER TABLE org_provider_profile ADD CONSTRAINT org_provider_profile_employment_type_check CHECK (employment_type IN ('full_time','part_time','per_diem','on_call')); CREATE INDEX idx_org_provider_profile_org ON org_provider_profile(organization_id); CREATE INDEX idx_org_provider_profile_type ON org_provider_profile(provider_type); CREATE INDEX idx_org_provider_profile_specialties ON org_provider_profile USING gin(specialties); ALTER TABLE org_provider_profile ENABLE ROW LEVEL SECURITY; CREATE POLICY provider_profile_self_read ON org_provider_profile FOR SELECT USING (person_id = get_my_person_id()); CREATE POLICY provider_profile_org_read ON org_provider_profile FOR SELECT USING (is_org_member(organization_id)); CREATE POLICY provider_profile_admin_write ON org_provider_profile FOR ALL USING (is_org_admin(organization_id)); CREATE POLICY provider_profile_service ON org_provider_profile FOR ALL TO service_role USING (true); COMMENT ON TABLE org_provider_profile IS 'Provider org-context profile. Differentiates clinician/trainer/pilates etc.'; CREATE TABLE org_client_profile (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL REFERENCES organizations(id), person_id uuid NOT NULL REFERENCES persons(id), client_type text NOT NULL DEFAULT 'patient', service_line text, care_setting text DEFAULT 'in_clinic', primary_diagnosis text, risk_flags text[] DEFAULT ARRAY[]::text[], goals_summary text, payer_type text DEFAULT 'self_pay', insurance_info jsonb DEFAULT '{}'::jsonb, referral_source text, metadata jsonb DEFAULT '{}'::jsonb, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), UNIQUE(organization_id, person_id)); ALTER TABLE org_client_profile ADD CONSTRAINT org_client_profile_client_type_check CHECK (client_type IN ('patient','customer','wellness_member','research_subject')); ALTER TABLE org_client_profile ADD CONSTRAINT org_client_profile_service_line_check CHECK (service_line IS NULL OR service_line IN ('MSK','neuro','sports','geriatric','pediatric','cardiopulmonary','wellness','fitness','rehabilitation','mixed')); ALTER TABLE org_client_profile ADD CONSTRAINT org_client_profile_care_setting_check CHECK (care_setting IN ('in_clinic','home_visit','remote','hybrid')); ALTER TABLE org_client_profile ADD CONSTRAINT org_client_profile_payer_type_check CHECK (payer_type IN ('self_pay','insurance','government','corporate','mixed')); CREATE INDEX idx_org_client_profile_org ON org_client_profile(organization_id); CREATE INDEX idx_org_client_profile_service_line ON org_client_profile(service_line); CREATE INDEX idx_org_client_profile_care_setting ON org_client_profile(care_setting); ALTER TABLE org_client_profile ENABLE ROW LEVEL SECURITY; CREATE POLICY client_profile_self_read ON org_client_profile FOR SELECT USING (person_id = get_my_person_id()); CREATE POLICY client_profile_org_read ON org_client_profile FOR SELECT USING (is_org_member(organization_id)); CREATE POLICY client_profile_admin_write ON org_client_profile FOR ALL USING (is_org_admin(organization_id)); CREATE POLICY client_profile_service ON org_client_profile FOR ALL TO service_role USING (true); COMMENT ON TABLE org_client_profile IS 'Client org-context profile. service_line, care_setting, payer_type.'; CREATE TABLE org_caregiver_link (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL REFERENCES organizations(id), caregiver_person_id uuid NOT NULL REFERENCES persons(id), client_person_id uuid NOT NULL REFERENCES persons(id), relationship text NOT NULL, can_view_records boolean DEFAULT false, can_book_appointments boolean DEFAULT true, can_view_billing boolean DEFAULT false, can_communicate boolean DEFAULT true, permissions jsonb DEFAULT '{}'::jsonb, status text NOT NULL DEFAULT 'active', verified_at timestamptz, verified_by uuid REFERENCES persons(id), notes text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), UNIQUE(organization_id, caregiver_person_id, client_person_id)); ALTER TABLE org_caregiver_link ADD CONSTRAINT org_caregiver_link_relationship_check CHECK (relationship IN ('parent','spouse','child','sibling','guardian','legal_representative','friend','other')); ALTER TABLE org_caregiver_link ADD CONSTRAINT org_caregiver_link_status_check CHECK (status IN ('active','inactive','pending_verification','revoked')); ALTER TABLE org_caregiver_link ADD CONSTRAINT org_caregiver_link_not_self CHECK (caregiver_person_id != client_person_id); CREATE INDEX idx_org_caregiver_link_org ON org_caregiver_link(organization_id); CREATE INDEX idx_org_caregiver_link_caregiver ON org_caregiver_link(caregiver_person_id); CREATE INDEX idx_org_caregiver_link_client ON org_caregiver_link(client_person_id); ALTER TABLE org_caregiver_link ENABLE ROW LEVEL SECURITY; CREATE POLICY caregiver_self_read ON org_caregiver_link FOR SELECT USING (caregiver_person_id = get_my_person_id() OR client_person_id = get_my_person_id()); CREATE POLICY caregiver_org_read ON org_caregiver_link FOR SELECT USING (is_org_member(organization_id)); CREATE POLICY caregiver_admin_write ON org_caregiver_link FOR ALL USING (is_org_admin(organization_id)); CREATE POLICY caregiver_service ON org_caregiver_link FOR ALL TO service_role USING (true); COMMENT ON TABLE org_caregiver_link IS 'Caregiver-client relationship within an org. Defines access for family/guardian.';;
